import sys
import json

def solve(data: str) -> str:
    try:
        value = json.loads(data)
    except json.JSONDecodeError:
        return 'invalid'
    valid = (isinstance(value, dict) and set(value) == {'answer','citations'} and isinstance(value['answer'], str) and isinstance(value['citations'], list) and all(isinstance(item,str) for item in value['citations']))
    return 'valid' if valid else 'invalid'

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
